// ============================================
// ИНИЦИАЛИЗАЦИЯ: Универсальная обработка входных данных
// ============================================

const inputData = $input.first().json;

// 1. Определяем откуда пришли данные
const messageObject = inputData.message || null;
const userInput = inputData.userInput || null;

// 2. НОВОЕ: Если данные от Set Text/Voice (нет поля message), загружаем от Telegram Trigger
let telegramMessage = null;

if (!messageObject && userInput) {
  // Данные от Set Text/Voice — загружаем недостающие данные
  try {
    telegramMessage = $('1. Telegram Trigger').first().json.message;
  } catch (e) {
    console.log('Failed to get Telegram Trigger data:', e);
    telegramMessage = null;
  }
}

// 3. Обрабатываем replyObject (может быть строкой!)
let replyObject = null;

if (inputData.replyObject) {
  if (typeof inputData.replyObject === 'string') {
    try {
      replyObject = JSON.parse(inputData.replyObject);
    } catch (e) {
      console.log('Failed to parse replyObject:', e);
      replyObject = null;
    }
  } else {
    replyObject = inputData.replyObject;
  }
}

// 4. Telegram данные: приоритет messageObject, затем telegramMessage, затем inputData
const telegramData = messageObject || telegramMessage || inputData;

// 5. Получаем reply если ещё не получили
if (!replyObject && telegramData.reply_to_message) {
  replyObject = telegramData.reply_to_message;
}

// 6. Извлекаем базовые данные (УНИВЕРСАЛЬНО!)
const chatId = telegramData.chat?.id || telegramData.chat_id || replyObject?.chat?.id;
const userId = telegramData.from?.id || telegramData.user_id || replyObject?.from?.id;
const username = telegramData.from?.username || telegramData.username || replyObject?.from?.username || '';
const messageId = telegramData.message_id || inputData.message_id;

// ============================================
// ПРОВЕРКА 1: Forwarded message
// ============================================

const forwardOrigin = telegramData.forward_origin || telegramData.forward_from;
const isForwarded = Boolean(forwardOrigin);

if (isForwarded) {
  return {
    json: {
      message_id: messageId,
      chat_id: chatId,
      user_id: userId,
      username: username,
      text: telegramData.text || telegramData.caption || '',
      is_forwarded: true,
      forwarded_content: {
        text: telegramData.text || telegramData.caption || '',
        forward_date: telegramData.forward_date
      },
      is_reply: false,
      timestamp: new Date().toISOString()
    }
  };
}

// ============================================
// ПРОВЕРКА 2: Фото + caption (ГОТОВАЯ ЗАДАЧА — v3.0)
// ============================================

const hasPhoto = !!telegramData.photo;
const caption = hasPhoto ? (telegramData.caption || null) : null;
const hasCaption = caption && caption.trim().length > 0;

if (hasPhoto && hasCaption) {
  return {
    json: {
      message_id: messageId,
      chat_id: chatId,
      user_id: userId,
      username: username,
      text: caption,
      is_reply: Boolean(replyObject),
      reply_to_message_id: replyObject?.message_id || null,
      has_photo: true,
      photo_file_id: telegramData.photo[telegramData.photo.length - 1].file_id,
      is_ready_photo_task: true,
      timestamp: new Date().toISOString()
    }
  };
}

// ============================================
// ПРОВЕРКА 3: Фото БЕЗ caption (нужен вопрос)
// ============================================

if (hasPhoto && !hasCaption) {
  return {
    json: {
      message_id: messageId,
      chat_id: chatId,
      user_id: userId,
      username: username,
      photo: telegramData.photo,
      caption: null,
      is_reply: Boolean(replyObject),
      reply_to_message_id: replyObject?.message_id || null,
      timestamp: new Date().toISOString()
    }
  };
}

// ============================================
// ПРОВЕРКА 4: Обычное сообщение (текст)
// ============================================

return {
  json: {
    message_id: messageId,
    chat_id: chatId,
    user_id: userId,
    username: username,
    text: userInput || telegramData.text || '',
    is_reply: Boolean(replyObject),
    reply_to_message_id: replyObject?.message_id || null,
    timestamp: new Date().toISOString()
  }
};

const command = $json.text?.toLowerCase().trim() || '';
const chatId = $json.chat_id;
const messageId = $json.message_id;

// Определяем тип команды
let commandType = 'unknown';

if (command === '/stop') {
  commandType = 'stop';
} else if (command === '/start') {
  commandType = 'start';
}

return {
  json: {
    chat_id: chatId,
    message_id: messageId,
    command: commandType,
    original_command: command
  }
};

const photo = $json.photo;
const chatId = $json.chat_id;
const messageId = $json.message_id;

if (!photo || !Array.isArray(photo) || photo.length === 0) {
  throw new Error('No photo found in message');
}

// Получаем самое большое фото
const photoFileId = photo[photo.length - 1].file_id;

// ✅ ВСЕГДА save_and_ask (потому что caption уже обработан в ЭТАП 2)
return {
  json: {
    chat_id: chatId,
    message_id: messageId,
    photo_file_id: photoFileId,
    action: 'save_and_ask'
  }
};

// ============================================
// ПРОВЕРКА: Откуда пришли данные?
// ============================================

const inputData = $input.first().json;
const messageData = $('9. Prepare Message Data').first().json;

// ============================================
// CASE 1: Данные от Load Context (RPC) — уже есть контекст!
// ============================================

if (inputData.context_type) {
  let content = inputData.content;
  if (typeof content === 'string') {
    try {
      content = JSON.parse(content);
    } catch (e) {
      content = null;
    }
  }

  let contextType = inputData.context_type;
  if (contextType === 'photo_temp') {
    contextType = 'photo';
  } else if (contextType === 'forwarded_temp') {
    contextType = 'forwarded';
  }

  // Базовая структура context
  const contextData = {
    context_type: contextType,
    has_photo: contextType === 'photo',
    photo_file_id: content?.photo_file_id || null,
    has_forwarded: contextType === 'forwarded',
    forwarded_content: contextType === 'forwarded' ? content : null,
    task_id: inputData.task_id,
    content: content
  };

  // ✅ НОВОЕ: Парсим структуру для POST
  if (contextType === 'post') {
    contextData.content = {
      post_text: content?.text || '',
      photo_file_id: content?.photo_file_id || null,
      version: content?.version || 1,
      sources: content?.sources || []
    };
  }

  return {
    json: {
      user_message: messageData.text,
      chat_id: messageData.chat_id,
      message_id: messageData.message_id,
      user_id: messageData.user_id,
      reply_to_message_id: messageData.reply_to_message_id,
      context: contextData
    }
  };
}

// ВСЁ ОСТАЛЬНОЕ БЕЗ ИЗМЕНЕНИЙ!
// (CASE 2, CASE 0, БЛОК 4, БЛОК 5, ПРИОРИТЕТ 3 - НЕ ТРОГАЕМ)

// ============================================
// CASE 2: Implicit context (NO Reply)
// ============================================

const context = {
  context_type: null,
  content: null,
  task_id: null,
  has_forwarded: false,
  forwarded_content: null,
  has_photo: false,
  photo_file_id: null
};

if (messageData.is_ready_photo_task === true) {
  context.context_type = 'photo';
  context.has_photo = true;
  context.photo_file_id = messageData.photo_file_id;

  return {
    json: {
      user_message: messageData.text,
      chat_id: messageData.chat_id,
      message_id: messageData.message_id,
      user_id: messageData.user_id,
      reply_to_message_id: messageData.reply_to_message_id,
      context: context
    }
  };
}

let recentMessages = [];
try {
  const loadRecentData = $('27. Load Recent Messages').all();
  if (loadRecentData && loadRecentData.length > 0) {
    recentMessages = loadRecentData.map(item => {
      const json = item.json;
      if (json.content_data && typeof json.content_data === 'string') {
        try {
          json.content_data = JSON.parse(json.content_data);
        } catch (e) {
          console.log('Failed to parse content_data:', e);
        }
      }
      return json;
    });
  }
} catch (e) {
  recentMessages = [];
}

if (recentMessages.length > 0) {
  const clearCommand = recentMessages.find(m => 
    m.message_type === 'command' && 
    (m.content_data?.command === 'stop' || m.content_data?.command === 'start')
  );

  if (clearCommand) {
    console.log(`[COMMAND] Found /${clearCommand.content_data.command}, checking if it clears context`);

    const lastPendingMessage = recentMessages.find(m =>
      m.message_type === 'system' && 
      m.content_data && 
      (m.content_data.pending_photo || m.content_data.pending_forwarded)
    );

    if (lastPendingMessage) {
      const commandTime = new Date(clearCommand.created_at).getTime();
      const pendingTime = new Date(lastPendingMessage.created_at).getTime();

      if (commandTime > pendingTime) {
        console.log(`[COMMAND] Clearing implicit context (/${clearCommand.content_data.command} is newer than pending)`);

        return {
          json: {
            user_message: messageData.text,
            chat_id: messageData.chat_id,
            message_id: messageData.message_id,
            user_id: messageData.user_id,
            reply_to_message_id: messageData.reply_to_message_id,
            context: {
              context_type: null,
              content: null,
              task_id: null,
              has_forwarded: false,
              forwarded_content: null,
              has_photo: false,
              photo_file_id: null
            }
          }
        };
      } else {
        console.log(`[COMMAND] /${clearCommand.content_data.command} is older than pending, ignoring`);
      }
    } else {
      console.log(`[COMMAND] No pending context found, nothing to clear`);
    }
  }
}

if (recentMessages.length > 0) {
  const lastSystemMessage = recentMessages
    .filter(m => m.message_type === 'system' && m.content_data)
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];

  if (lastSystemMessage) {
    if (lastSystemMessage.content_data.pending_photo) {
      const photoMessageId = lastSystemMessage.content_data.pending_photo;
      const photoMessage = recentMessages.find(m => m.telegram_message_id === photoMessageId);

      if (photoMessage && photoMessage.content_data) {
        context.context_type = 'photo';
        context.has_photo = true;
        context.photo_file_id = photoMessage.content_data.photo_file_id;
      }
    }
    else if (lastSystemMessage.content_data.pending_forwarded) {
      const forwardedMessageId = lastSystemMessage.content_data.pending_forwarded;
      const forwardedMessage = recentMessages.find(m => m.telegram_message_id === forwardedMessageId);

      if (forwardedMessage && forwardedMessage.content_data) {
        context.context_type = 'forwarded';
        context.has_forwarded = true;
        context.forwarded_content = {
          text: forwardedMessage.content_data.text,
          forwarded_date: forwardedMessage.content_data.forwarded_date
        };
      }
    }
  }
}

if (!context.context_type && !messageData.reply_to_message_id) {
  const allItems = $input.all();

  const lastSentMessage = allItems
    .filter(item => 
      item.json?.message_type && 
      (item.json.message_type === 'longread' || item.json.task_id) &&
      item.json.created_at
    )
    .sort((a, b) => new Date(b.json.created_at) - new Date(a.json.created_at))[0];

  if (lastSentMessage) {
    console.log(`[TEMPORAL PROXIMITY] Found sent_message: ${lastSentMessage.json.message_type}`);

    if (lastSentMessage.json.message_type === 'longread') {
      context.context_type = 'longread';
      context.content = lastSentMessage.json.content_data;
      if (typeof context.content === 'string') {
        try {
          context.content = JSON.parse(context.content);
        } catch (e) {
          console.log('[TEMPORAL PROXIMITY] Failed to parse longread:', e);
        }
      }
    }
    else if (lastSentMessage.json.task_id) {
      const taskData = allItems.find(item => 
        item.json?.id === lastSentMessage.json.task_id &&
        item.json?.department === 'research'
      );

      if (taskData) {
        context.context_type = 'research';
        context.task_id = lastSentMessage.json.task_id;
        context.content = taskData.json;
      }
    }
  }
}

if (!context.context_type && messageData.reply_to_message_id) {
  const allItems = $input.all();
  const replyTarget = allItems.find(item => 
    item.json?.telegram_message_id === messageData.reply_to_message_id
  );

  if (replyTarget) {
    console.log(`[REPLY CONTEXT] Found reply target: ${replyTarget.json.message_type}, task_id: ${replyTarget.json.task_id}`);

    if (replyTarget.json.message_type === 'longread') {
      context.context_type = 'longread';
      context.content = replyTarget.json.content_data;
      if (typeof context.content === 'string') {
        try {
          context.content = JSON.parse(context.content);
        } catch (e) {
          console.log('[REPLY CONTEXT] Failed to parse longread content:', e);
        }
      }
    }
    else if (replyTarget.json.task_id) {
      context.context_type = 'task';
      context.task_id = replyTarget.json.task_id;
    }
    // ✅ НОВОЕ: Обработка POST в allItems
    else if (replyTarget.json.message_type === 'post') {
  context.context_type = 'post';
  context.content = {
    post_text: replyTarget.json.content_data?.text || '',  // ✅ Исправлено!
    photo_file_id: replyTarget.json.content_data?.photo_file_id || null,
    version: replyTarget.json.content_data?.version || 1,
    sources: replyTarget.json.content_data?.sources || []
  };
}
  } else {
    console.log(`[REPLY CONTEXT] Reply target not found: message_id ${messageData.reply_to_message_id}`);
  }
}

return {
  json: {
    user_message: messageData.text,
    chat_id: messageData.chat_id,
    message_id: messageData.message_id,
    user_id: messageData.user_id,
    reply_to_message_id: messageData.reply_to_message_id,
    context: context
  }
};

const data = $input.first().json;

// ============================================
// USER PROMPT: ТОЛЬКО ФАКТЫ!
// ============================================

let userPrompt = `**Запрос пользователя:**
"${data.user_message || data.text}"
`;

// Контекст (только факты)
if (data.context && data.context.context_type) {

  userPrompt += `\n**Контекст:**\n`;

  if (data.context.context_type === 'photo') {
    userPrompt += `- Тип: фото\n`;
    userPrompt += `- Photo ID: ${data.context.photo_file_id}\n`;
  }

  else if (data.context.context_type === 'forwarded') {
    userPrompt += `- Тип: пересланное сообщение\n`;
    userPrompt += `- Текст: "${data.context.forwarded_content.text}"\n`;
  }

  else if (data.context.context_type === 'longread') {
    userPrompt += `- Тип: лонгрид\n`;
    if (data.context.content && data.context.content.news_list) {
      userPrompt += `- Доступные новости:\n`;
      userPrompt += data.context.content.news_list
        .map(n => `  ${n.id}. ${n.title}`)
        .join('\n') + '\n';
    }
  }

  else if (data.context.context_type === 'task') {
    userPrompt += `- Тип: существующая задача\n`;
    userPrompt += `- Task ID: ${data.context.task_id}\n`;
  }

  else {
    userPrompt += `- Тип: ${data.context.context_type}\n`;
  }

} else {
  userPrompt += `\n**Контекст:** отсутствует\n`;
}

// ============================================
// БЕЗОПАСНОЕ ОБРАЩЕНИЕ К LOAD ACTIVE TASKS
// ============================================

let completedTasks = [];

try {
  const loadTasksData = $('26. Load Active Tasks').all();
  if (loadTasksData && loadTasksData.length > 0) {
    completedTasks = loadTasksData;
  }
} catch (e) {
  // Load Active Tasks не выполнялась или вернула ошибку
  completedTasks = [];
}

// Фильтруем валидные задачи
const validTasks = completedTasks.filter(task => task.json && task.json.id);

// Completed задачи (доступны для iterative cycles)
if (validTasks.length > 0) {
  userPrompt += `\n**Задачи со статусом completed (доступны для task_update):**\n`;
  validTasks.forEach(task => {
    const t = task.json;
    userPrompt += `- ${t.department}: "${t.initial_prompt}" (ID: ${t.id}, обновлено: ${new Date(t.updated_at).toLocaleString('ru-RU')})\n`;
  });
} else {
  userPrompt += `\n**Задачи со статусом completed:** нет\n`;
}

// ============================================
// ИЗВЛЕКАЕМ ДАННЫЕ ДЛЯ ORIGINAL_DATA
// ============================================

const completedTasksData = validTasks.map(task => task.json);

// ============================================
// ВОЗВРАЩАЕМ С COMPLETED_TASKS
// ============================================

return {
  json: {
    user_prompt: userPrompt.trim(),
    original_data: {
      ...data,
      completed_tasks: completedTasksData  // ← КЛЮЧЕВОЕ ИЗМЕНЕНИЕ
    }
  }
};

const decision = $input.first().json.output;
const originalData = $('30. Prepare AI Prompt').first().json.original_data;
const context = originalData.context;

let sourceData = null;

// ============================================
// ПРИОРИТЕТ #1-4: Context-based source_data
// ============================================

if (context && context.context_type) {

  // Приоритет 1: Reply на longread
  if (context.context_type === 'longread') {
    sourceData = {
      type: 'longread',
      news_list: context.content.news_list,
      user_instruction: decision.user_request
    };
  }

  // Приоритет 2: Forwarded message
  else if (context.context_type === 'forwarded') {
    sourceData = {
      type: 'forwarded_message',
      text: context.forwarded_content.text,
      forwarded_date: context.forwarded_content.forwarded_date
    };
  }

  // Приоритет 3: Photo
  else if (context.context_type === 'photo') {
    sourceData = {
      type: 'photo',
      photo_file_id: context.photo_file_id
    };
  }

  // Приоритет 3.5: Post (reply на пост)
  else if (context.context_type === 'post') {
    sourceData = {
      type: 'post',
      task_id: context.task_id,
      post_text: context.content?.post_text || '',
      photo_file_id: context.content?.photo_file_id || null,
      version: context.content?.version || 1,
      sources: context.content?.sources || []
    };
    console.log('[PREPARE NEW TASK] Post source_data from reply, text length:', sourceData.post_text.length);
  }

  // Приоритет 4: Task (обновление)
  else if (context.context_type === 'task') {
    sourceData = null;
  }

  // Приоритет 5: Research
  else if (context.context_type === 'research') {
    sourceData = {
      type: 'research',
      content: context.content?.content || null,
      sources: context.content?.sources || []
    };
  }

  else {
    sourceData = null;
  }
}

// ПРИОРИТЕТ #5: Неявные ссылки на completed tasks
if (!sourceData && decision.user_request) {
  const implicitReferences = [
    'для этого поста',
    'к этому посту', 
    'про этот пост',
    'для того поста',
    'к той новости',
    'про ту новость',
    'для этой новости',
    'к этой новости'
  ];

  const requestLower = decision.user_request.toLowerCase();
  const hasImplicitReference = implicitReferences.some(phrase => 
    requestLower.includes(phrase)
  );

  if (hasImplicitReference && originalData.completed_tasks?.length > 0) {
    const lastCopywritingTask = originalData.completed_tasks
      .filter(t => t.department === 'copywriting')
      .sort((a, b) => new Date(b.updated_at) - new Date(a.updated_at))[0];

    if (lastCopywritingTask) {
      sourceData = {
        reference_task_id: lastCopywritingTask.id,  // ✅ Только ID
        reference_type: 'post',                     // ✅ Тип источника
        user_request: decision.user_request         // ✅ Запрос
      };

      console.log('[PREPARE NEW TASK] Implicit reference detected, reference_task_id:', lastCopywritingTask.id);
    }
  }
}
// ============================================
// ФОРМИРУЕМ ИТОГОВЫЙ ОБЪЕКТ
// ============================================

return {
  json: {
    chat_id: originalData.chat_id,
    user_id: originalData.user_id,
    department: decision.department,
    status: 'created',
    initial_prompt: decision.user_request,
    source_data: sourceData,
    agent_output: {
      current_version: 1,
      versions: []
    }
  }
};

const decision = $input.first().json.output;
const originalData = $('30. Prepare AI Prompt').first().json.original_data;
const context = originalData.context;

let taskId = null;
let taskData = null;
let fullAgentOutput = null;

// Загрузка completed tasks
let completedTasks = [];
try {
  const loadTasksData = $('26. Load Active Tasks').all();
  if (loadTasksData && loadTasksData.length > 0) {
    completedTasks = loadTasksData.map(item => item.json);
  }
} catch (e) {
  console.log('[Prepare Update Task Data] Failed to load completed tasks:', e);
  completedTasks = [];
}

// ПРИОРИТЕТ #1: target_task_id от AI Agent
if (decision.target_task_id) {
  const targetTask = completedTasks.find(task => task.id === decision.target_task_id);

  if (targetTask) {
    taskId = targetTask.id;
    taskData = {
      current_version: targetTask.agent_output?.current_version || 0,
      department: targetTask.department
    };
    fullAgentOutput = targetTask.agent_output;
  } else {
    throw new Error(`Task ${decision.target_task_id} not found in completed tasks`);
  }
}

// ПРИОРИТЕТ #2: REPLY контекст
else if (context.task_id) {
  taskId = context.task_id;
  const targetTask = completedTasks.find(task => task.id === context.task_id);

  if (targetTask) {
    taskData = {
      current_version: targetTask.agent_output?.current_version || 0,
      department: targetTask.department
    };
    fullAgentOutput = targetTask.agent_output;
  } else {
    taskData = {
      current_version: 0,
      department: decision.department
    };
    fullAgentOutput = { current_version: 0, versions: [] };
  }
}

// ПРИОРИТЕТ #3: Последняя задача с matching department
else if (completedTasks.length > 0 && decision.department) {
  const tasksInDepartment = completedTasks.filter(
    task => task.department === decision.department
  );

  if (tasksInDepartment.length > 0) {
    const targetTask = tasksInDepartment[0];
    taskId = targetTask.id;
    taskData = {
      current_version: targetTask.agent_output?.current_version || 0,
      department: targetTask.department
    };
    fullAgentOutput = targetTask.agent_output;
  }
}

// FALLBACK: задачи не нашли
if (!taskId) {
  const hint = decision.department && completedTasks.length > 0
    ? `No ${decision.department} tasks found in recent history. Reply to a specific task message or create a new task.`
    : 'No recent completed tasks found. Reply to a task message or create a new task.';

  throw new Error(hint);
}

// Формируем обновлённый agent_output
if (typeof fullAgentOutput === 'string') {
  try {
    fullAgentOutput = JSON.parse(fullAgentOutput);
  } catch (e) {
    fullAgentOutput = { current_version: 0, versions: [] };
  }
}

let versions = fullAgentOutput?.versions || [];

// Создаём новую версию
const newVersion = {
  version: (fullAgentOutput?.current_version || 0) + 1,
  user_request: decision.user_request,
  agent_response: null,
  timestamp: new Date().toISOString()
};

// Проверка безопасности (логируем, не блокируем)
if (versions.length > 0) {
  const lastVersion = versions[versions.length - 1];
  if (lastVersion.version && lastVersion.version !== newVersion.version - 1) {
    console.warn(`[PREPARE UPDATE] Version sequence warning: last=${lastVersion.version}, new=${newVersion.version}`);
  }
}

versions.push(newVersion);

const updatedAgentOutput = {
  versions: versions,
  current_version: newVersion.version
};

return {
  json: {
    task_id: taskId,
    agent_output: updatedAgentOutput,
    status: 'in_progress',
    department: taskData?.department || decision.department,
    reply_to_message_id: originalData.reply_to_message_id
  }
};

